@startuml
title Index (ISP refactor)

package "edu" {
  package "tec" {
    package "ic6821" {
      package "fulltextsearch" {
        package "index" {
          interface IIndex <<I>> {
            + index(String term, File):void
            + search(String term):Set<File>
            + isPersistent():boolean
          }

          class PersistentIndex <<I>> {
            + persist():void
            + restore():boolean
          }

          class InMemoryMapIndex <<C>> {
            - index: Map<String, Set<File>>
          }

          class MapIndex <<C>> {
            - indexFile : File
            + MapIndex(:File, :Index)
          }

          ' Relationships
          PersistentIndex --|> IIndex
          InMemoryMapIndex ..|> IIndex
          MapIndex .up.|> PersistentIndex
          MapIndex --> InMemoryMapIndex : «delegate»\nindex
        }
      }
    }
  }
}

@enduml
